const container = document.getElementById("storeContainer");
const searchInput = document.getElementById("searchInput");

/* ===================== SORT ULUBIONYCH ===================== */
function sortFavoritesFirst(list) {

  const fav = JSON.parse(localStorage.getItem("favorites")) || [];

  return [...list].sort((a, b) => {
    const aFav = fav.includes(a.name);
    const bFav = fav.includes(b.name);

    return bFav - aFav;
  });
}

/* ===================== WYŚWIETLANIE ===================== */
function displayStores(list) {

  const sorted = sortFavoritesFirst(list);

  container.innerHTML = "";

  sorted.forEach(store => {

    const fav = JSON.parse(localStorage.getItem("favorites")) || [];

    const isFav = fav.includes(store.name);

    const opinions =
      JSON.parse(localStorage.getItem(store.name)) || [];

    let opinionsHTML = "";

    opinions.forEach((op, i) => {

      opinionsHTML += `
        <li>
          ${op}
          <button onclick="removeOpinion('${store.name}', ${i})">❌</button>
        </li>
      `;
    });

    container.innerHTML += `
      <div class="card">

        <img src="${store.image}">

        <div class="card-content">

          <h2>${store.name}</h2>

          <p>${store.category}</p>
          <p>${store.description}</p>
          <p>${store.location}</p>

          ${
            isFav
            ? `<button onclick="removeFavorite('${store.name}')">⭐ Usuń z ulubionych</button>`
            : `<button onclick="favoriteStore('${store.name}')">☆ Dodaj do ulubionych</button>`
          }

          <hr>

          <ul>
            ${opinionsHTML}
          </ul>

          <input
            id="input-${store.name}"
            placeholder="Dodaj opinię"
          >

          <button onclick="addOpinion('${store.name}')">
            Dodaj
          </button>

        </div>

      </div>
    `;
  });
}

/* ===================== FILTRY ===================== */
function filterStores(category) {

  if (category === "Wszystkie") {

    currentStores = [...stores];

  } else {

    currentStores =
      stores.filter(store => store.category === category);
  }

  displayStores(currentStores);
}

/* ===================== ULUBIONE ===================== */
function favoriteStore(storeName) {

  let fav =
    JSON.parse(localStorage.getItem("favorites")) || [];

  if (!fav.includes(storeName)) {

    fav.push(storeName);
  }

  localStorage.setItem(
    "favorites",
    JSON.stringify(fav)
  );

  displayStores(currentStores);
}

function removeFavorite(storeName) {

  let fav =
    JSON.parse(localStorage.getItem("favorites")) || [];

  fav = fav.filter(f => f !== storeName);

  localStorage.setItem(
    "favorites",
    JSON.stringify(fav)
  );

  displayStores(currentStores);
}

function showFavorites() {

  const fav =
    JSON.parse(localStorage.getItem("favorites")) || [];

  currentStores =
    stores.filter(store => fav.includes(store.name));

  displayStores(currentStores);
}

/* ===================== OPINIE ===================== */
function addOpinion(name) {

  const input =
    document.getElementById(`input-${name}`);

  if (!input.value.trim()) return;

  let data =
    JSON.parse(localStorage.getItem(name)) || [];

  data.push(input.value);

  localStorage.setItem(
    name,
    JSON.stringify(data)
  );

  displayStores(currentStores);
}

function removeOpinion(name, i) {

  let data =
    JSON.parse(localStorage.getItem(name)) || [];

  data.splice(i, 1);

  localStorage.setItem(
    name,
    JSON.stringify(data)
  );

  displayStores(currentStores);
}

/* ===================== SEARCH ===================== */
searchInput.addEventListener("input", () => {

  const val =
    searchInput.value.toLowerCase();

  currentStores = stores.filter(store =>
    store.name.toLowerCase().includes(val)
  );

  displayStores(currentStores);
});

/* ===================== START ===================== */
displayStores(currentStores);